type IssuingCardholderRequirementsDisabledReason =
    | Listed
    | [<JsonPropertyName("rejected.listed")>] RejectedListed
    | [<JsonPropertyName("requirements.past_due")>] RequirementsPastDue
    | UnderReview

type IssuingCardholderRequirementsPastDue =
    | [<JsonPropertyName("company.tax_id")>] CompanyTaxId
    | [<JsonPropertyName("individual.card_issuing.user_terms_acceptance.date")>] IndividualCardIssuingUserTermsAcceptanceDate
    | [<JsonPropertyName("individual.card_issuing.user_terms_acceptance.ip")>] IndividualCardIssuingUserTermsAcceptanceIp
    | [<JsonPropertyName("individual.dob.day")>] IndividualDobDay
    | [<JsonPropertyName("individual.dob.month")>] IndividualDobMonth
    | [<JsonPropertyName("individual.dob.year")>] IndividualDobYear
    | [<JsonPropertyName("individual.first_name")>] IndividualFirstName
    | [<JsonPropertyName("individual.last_name")>] IndividualLastName
    | [<JsonPropertyName("individual.verification.document")>] IndividualVerificationDocument

type IssuingCardholderRequirements =
    {
        /// If `disabled_reason` is present, all cards will decline authorizations with `cardholder_verification_required` reason.
        DisabledReason: IssuingCardholderRequirementsDisabledReason option
        /// Array of fields that need to be collected in order to verify and re-enable the cardholder.
        PastDue: IssuingCardholderRequirementsPastDue list option
    }

[<Struct>]
type IssuingCardholderStatus =
    | Active
    | Blocked
    | Inactive

[<Struct>]
type IssuingCardholderType =
    | Company
    | Individual

/// An Issuing `Cardholder` object represents an individual or business entity who is [issued](https://docs.stripe.com/issuing) cards.
/// Related guide: [How to create a cardholder](https://docs.stripe.com/issuing/cards/virtual/issue-cards#create-cardholder)
type IssuingCardholder =
    {
        Billing: IssuingCardholderAddress
        /// Additional information about a `company` cardholder.
        Company: IssuingCardholderCompany option
        /// Time at which the object was created. Measured in seconds since the Unix epoch.
        Created: DateTime
        /// The cardholder's email address.
        Email: string option
        /// Unique identifier for the object.
        Id: string
        /// Additional information about an `individual` cardholder.
        Individual: IssuingCardholderIndividual option
        /// If the object exists in live mode, the value is `true`. If the object exists in test mode, the value is `false`.
        Livemode: bool
        /// Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format.
        Metadata: Map<string, string>
        /// The cardholder's name. This will be printed on cards issued to them.
        Name: string
        /// The cardholder's phone number. This is required for all cardholders who will be creating EU cards. See the [3D Secure documentation](https://docs.stripe.com/issuing/3d-secure#when-is-3d-secure-applied) for more details.
        PhoneNumber: string option
        /// The cardholder’s preferred locales (languages), ordered by preference. Locales can be `da`, `de`, `en`, `es`, `fr`, `it`, `pl`, or `sv`.
        ///  This changes the language of the [3D Secure flow](https://docs.stripe.com/issuing/3d-secure) and one-time password messages sent to the cardholder.
        PreferredLocales: IssuingCardholderPreferredLocales list option
        Requirements: IssuingCardholderRequirements
        /// Rules that control spending across this cardholder's cards. Refer to our [documentation](https://docs.stripe.com/issuing/controls/spending-controls) for more details.
        SpendingControls: IssuingCardholderAuthorizationControls option
        /// Specifies whether to permit authorizations on this cardholder's cards.
        Status: IssuingCardholderStatus
        /// One of `individual` or `company`. See [Choose a cardholder type](https://docs.stripe.com/issuing/other/choose-cardholder) for more details.
        Type: IssuingCardholderType
    }

type IssuingAuthorizationCardholder'AnyOf =
    | String of string
    | IssuingCardholder of IssuingCardholder

type IssuingAuthorizationFleetCardholderPromptData =
    {
        /// [Deprecated] An alphanumeric ID, though typical point of sales only support numeric entry. The card program can be configured to prompt for a vehicle ID, driver ID, or generic ID.
        AlphanumericId: string option
        /// Driver ID.
        DriverId: string option
        /// Odometer reading.
        Odometer: int option
        /// An alphanumeric ID. This field is used when a vehicle ID, driver ID, or generic ID is entered by the cardholder, but the merchant or card network did not specify the prompt type.
        UnspecifiedId: string option
        /// User ID.
        UserId: string option
        /// Vehicle number.
        VehicleNumber: string option
    }

[<Struct>]
type IssuingAuthorizationFleetDataPurchaseType =
    | FuelAndNonFuelPurchase
    | FuelPurchase
    | NonFuelPurchase

[<Struct>]
type IssuingAuthorizationFleetDataServiceType =
    | FullService
    | NonFuelTransaction
    | SelfService

type IssuingAuthorizationFleetFuelPriceData =
    {
        /// Gross fuel amount that should equal Fuel Quantity multiplied by Fuel Unit Cost, inclusive of taxes.
        GrossAmountDecimal: string option
    }

type IssuingAuthorizationFleetNonFuelPriceData =
    {
        /// Gross non-fuel amount that should equal the sum of the line items, inclusive of taxes.
        GrossAmountDecimal: string option
    }

type IssuingAuthorizationFleetTaxData =
    {
        /// Amount of state or provincial Sales Tax included in the transaction amount. `null` if not reported by merchant or not subject to tax.
        LocalAmountDecimal: string option
        /// Amount of national Sales Tax or VAT included in the transaction amount. `null` if not reported by merchant or not subject to tax.
        NationalAmountDecimal: string option
    }

type IssuingAuthorizationFleetReportedBreakdown =
    {
        /// Breakdown of fuel portion of the purchase.
        Fuel: IssuingAuthorizationFleetFuelPriceData option
        /// Breakdown of non-fuel portion of the purchase.
        NonFuel: IssuingAuthorizationFleetNonFuelPriceData option
        /// Information about tax included in this transaction.
        Tax: IssuingAuthorizationFleetTaxData option
    }

type IssuingAuthorizationFleetData =
    {
        /// Answers to prompts presented to the cardholder at the point of sale. Prompted fields vary depending on the configuration of your physical fleet cards. Typical points of sale support only numeric entry.
        CardholderPromptData: IssuingAuthorizationFleetCardholderPromptData option
        /// The type of purchase.
        PurchaseType: IssuingAuthorizationFleetDataPurchaseType option
        /// More information about the total amount. Typically this information is received from the merchant after the authorization has been approved and the fuel dispensed. This information is not guaranteed to be accurate as some merchants may provide unreliable data.
        ReportedBreakdown: IssuingAuthorizationFleetReportedBreakdown option
        /// The type of fuel service.
        ServiceType: IssuingAuthorizationFleetDataServiceType option
    }

[<Struct>]
type IssuingAuthorizationFraudChallengeStatus =
    | Expired
    | Pending
    | Rejected
    | Undeliverable
    | Verified

[<Struct>]
type IssuingAuthorizationFraudChallengeUndeliverableReason =
    | NoPhoneNumber
    | UnsupportedPhoneNumber

type IssuingAuthorizationFraudChallenge =
    {
        /// The status of the fraud challenge.
        Status: IssuingAuthorizationFraudChallengeStatus
        /// If the challenge is not deliverable, the reason why.
        UndeliverableReason: IssuingAuthorizationFraudChallengeUndeliverableReason option
    }

[<Struct>]
type IssuingAuthorizationFuelDataType =
    | Diesel
    | Other
    | UnleadedPlus
    | UnleadedRegular
    | UnleadedSuper

type IssuingAuthorizationFuelDataUnit =
    | ChargingMinute
    | ImperialGallon
    | Kilogram
    | KilowattHour
    | Liter
    | Other
    | Pound
    | UsGallon

type IssuingAuthorizationFuelData =
    {
        /// [Conexxus Payment System Product Code](https://www.conexxus.org/conexxus-payment-system-product-codes) identifying the primary fuel product purchased.
        IndustryProductCode: string option
        /// The quantity of `unit`s of fuel that was dispensed, represented as a decimal string with at most 12 decimal places.
        QuantityDecimal: string option
        /// The type of fuel that was purchased.
        Type: IssuingAuthorizationFuelDataType option
        /// The units for `quantity_decimal`.
        Unit: IssuingAuthorizationFuelDataUnit option
        /// The cost in cents per each unit of fuel, represented as a decimal string with at most 12 decimal places.
        UnitCostDecimal: string option
    }

type IssuingAuthorizationMerchantData =
    {
        /// A categorization of the seller's type of business. See our [merchant categories guide](https://docs.stripe.com/issuing/merchant-categories) for a list of possible values.
        Category: string
        /// The merchant category code for the seller’s business
        CategoryCode: string
        /// City where the seller is located
        City: string option
        /// Country where the seller is located
        Country: IsoTypes.IsoCountryCode option
        /// Name of the seller
        Name: string option
        /// Identifier assigned to the seller by the card network. Different card networks may assign different network_id fields to the same merchant.
        NetworkId: string
        /// Postal code where the seller is located
        PostalCode: string option
        /// State where the seller is located
        State: string option
        /// The seller's tax identification number. Currently populated for French merchants only.
        TaxId: string option
        /// An ID assigned by the seller to the location of the sale.
        TerminalId: string option
        /// URL provided by the merchant on a 3DS request
        Url: string option
    }

type IssuingAuthorizationNetworkData =
    {
        /// Identifier assigned to the acquirer by the card network. Sometimes this value is not provided by the network; in this case, the value will be `null`.
        AcquiringInstitutionId: string option
        /// The System Trace Audit Number (STAN) is a 6-digit identifier assigned by the acquirer. Prefer `network_data.transaction_id` if present, unless you have special requirements.
        SystemTraceAuditNumber: string option
        /// Unique identifier for the authorization assigned by the card network used to match subsequent messages, disputes, and transactions.
        TransactionId: string option
    }

type IssuingAuthorizationPendingRequest =
    {
        /// The additional amount Stripe will hold if the authorization is approved, in the card's [currency](https://docs.stripe.com/api#issuing_authorization_object-pending-request-currency) and in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal).
        Amount: int
        /// Detailed breakdown of amount components. These amounts are denominated in `currency` and in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal).
        AmountDetails: IssuingAuthorizationAmountDetails option
        /// Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).
        Currency: IsoTypes.IsoCurrencyCode
        /// If set `true`, you may provide [amount](https://docs.stripe.com/api/issuing/authorizations/approve#approve_issuing_authorization-amount) to control how much to hold for the authorization.
        IsAmountControllable: bool
        /// The amount the merchant is requesting to be authorized in the `merchant_currency`. The amount is in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal).
        MerchantAmount: int
        /// The local currency the merchant is requesting to authorize.
        MerchantCurrency: IsoTypes.IsoCurrencyCode
        /// The card network's estimate of the likelihood that an authorization is fraudulent. Takes on values between 1 and 99.
        NetworkRiskScore: int option
    }

type IssuingAuthorizationRequestReason =
    | AccountDisabled
    | CardActive
    | CardCanceled
    | CardExpired
    | CardInactive
    | CardholderBlocked
    | CardholderInactive
    | CardholderVerificationRequired
    | InsecureAuthorizationMethod
    | InsufficientFunds
    | NetworkFallback
    | NotAllowed
    | PinBlocked
    | SpendingControls
    | SuspectedFraud
    | VerificationFailed
    | WebhookApproved
    | WebhookDeclined
    | WebhookError
    | WebhookTimeout

type IssuingAuthorizationRequest =
    {
        /// The `pending_request.amount` at the time of the request, presented in your card's currency and in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal). Stripe held this amount from your account to fund the authorization if the request was approved.
        Amount: int
        /// Detailed breakdown of amount components. These amounts are denominated in `currency` and in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal).
        AmountDetails: IssuingAuthorizationAmountDetails option
        /// Whether this request was approved.
        Approved: bool
        /// A code created by Stripe which is shared with the merchant to validate the authorization. This field will be populated if the authorization message was approved. The code typically starts with the letter "S", followed by a six-digit number. For example, "S498162". Please note that the code is not guaranteed to be unique across authorizations.
        AuthorizationCode: string option
        /// Time at which the object was created. Measured in seconds since the Unix epoch.
        Created: DateTime
        /// Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).
        Currency: IsoTypes.IsoCurrencyCode
        /// The `pending_request.merchant_amount` at the time of the request, presented in the `merchant_currency` and in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal).
        MerchantAmount: int
        /// The currency that was collected by the merchant and presented to the cardholder for the authorization. Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).
        MerchantCurrency: IsoTypes.IsoCurrencyCode
        /// The card network's estimate of the likelihood that an authorization is fraudulent. Takes on values between 1 and 99.
        NetworkRiskScore: int option
        /// When an authorization is approved or declined by you or by Stripe, this field provides additional detail on the reason for the outcome.
        Reason: IssuingAuthorizationRequestReason
        /// If the `request_history.reason` is `webhook_error` because the direct webhook response is invalid (for example, parsing errors or missing parameters), we surface a more detailed error message via this field.
        ReasonMessage: string option
        /// Time when the card network received an authorization request from the acquirer in UTC. Referred to by networks as transmission time.
        RequestedAt: DateTime option
    }

[<Struct>]
type IssuingAuthorizationStatus =
    | Closed
    | Expired
    | Pending
    | Reversed

[<Struct>]
type IssuingNetworkTokenDeviceType =
    | Other
    | Phone
    | Watch

type IssuingNetworkTokenDevice =
    {
        /// An obfuscated ID derived from the device ID.
        DeviceFingerprint: string option
        /// The IP address of the device at provisioning time.
        IpAddress: string option
        /// The geographic latitude/longitude coordinates of the device at provisioning time. The format is [+-]decimal/[+-]decimal.
        Location: string option
        /// The name of the device used for tokenization.
        Name: string option
        /// The phone number of the device used for tokenization.
        PhoneNumber: string option
        /// The type of device used for tokenization.
        Type: IssuingNetworkTokenDeviceType option
    }

type IssuingNetworkTokenMastercard =
    {
        /// A unique reference ID from MasterCard to represent the card account number.
        CardReferenceId: string option
        /// The network-unique identifier for the token.
        TokenReferenceId: string
        /// The ID of the entity requesting tokenization, specific to MasterCard.
        TokenRequestorId: string
        /// The name of the entity requesting tokenization, if known. This is directly provided from MasterCard.
        TokenRequestorName: string option
    }

[<Struct>]
type IssuingNetworkTokenNetworkDataType =
    | Mastercard
    | Visa

type IssuingNetworkTokenVisa =
    {
        /// A unique reference ID from Visa to represent the card account number.
        CardReferenceId: string option
        /// The network-unique identifier for the token.
        TokenReferenceId: string
        /// The ID of the entity requesting tokenization, specific to Visa.
        TokenRequestorId: string
        /// Degree of risk associated with the token between `01` and `99`, with higher number indicating higher risk. A `00` value indicates the token was not scored by Visa.
        TokenRiskScore: string option
    }

type IssuingNetworkTokenAddress =
    {
        /// The street address of the cardholder tokenizing the card.
        [<JsonPropertyName("line1")>]
        Line1: string
        /// The postal code of the cardholder tokenizing the card.
        PostalCode: string
    }

[<Struct>]
type IssuingNetworkTokenWalletProviderCardNumberSource =
    | App
    | Manual
    | OnFile
    | Other

type IssuingNetworkTokenWalletProviderReasonCodes =
    | AccountCardTooNew
    | AccountRecentlyChanged
    | AccountTooNew
    | AccountTooNewSinceLaunch
    | AdditionalDevice
    | DataExpired
    | DeferIdVDecision
    | DeviceRecentlyLost
    | GoodActivityHistory
    | HasSuspendedTokens
    | HighRisk
    | InactiveAccount
    | LongAccountTenure
    | LowAccountScore
    | LowDeviceScore
    | LowPhoneNumberScore
    | NetworkServiceError
    | OutsideHomeTerritory
    | ProvisioningCardholderMismatch
    | ProvisioningDeviceAndCardholderMismatch
    | ProvisioningDeviceMismatch
    | SameDeviceNoPriorAuthentication
    | SameDeviceSuccessfulPriorAuthentication
    | SoftwareUpdate
    | SuspiciousActivity
    | TooManyDifferentCardholders
    | TooManyRecentAttempts
    | TooManyRecentTokens

[<Struct>]
type IssuingNetworkTokenWalletProviderSuggestedDecision =
    | Approve
    | Decline
    | RequireAuth

type IssuingNetworkTokenWalletProvider =
    {
        /// The wallet provider-given account ID of the digital wallet the token belongs to.
        AccountId: string option
        /// An evaluation on the trustworthiness of the wallet account between 1 and 5. A higher score indicates more trustworthy.
        AccountTrustScore: int option
        /// The method used for tokenizing a card.
        CardNumberSource: IssuingNetworkTokenWalletProviderCardNumberSource option
        CardholderAddress: IssuingNetworkTokenAddress option
        /// The name of the cardholder tokenizing the card.
        CardholderName: string option
        /// An evaluation on the trustworthiness of the device. A higher score indicates more trustworthy.
        DeviceTrustScore: int option
        /// The hashed email address of the cardholder's account with the wallet provider.
        HashedAccountEmailAddress: string option
        /// The reasons for suggested tokenization given by the card network.
        ReasonCodes: IssuingNetworkTokenWalletProviderReasonCodes list option
        /// The recommendation on responding to the tokenization request.
        SuggestedDecision: IssuingNetworkTokenWalletProviderSuggestedDecision option
        /// The version of the standard for mapping reason codes followed by the wallet provider.
        SuggestedDecisionVersion: string option
    }

type IssuingNetworkTokenNetworkData =
    {
        Device: IssuingNetworkTokenDevice option
        Mastercard: IssuingNetworkTokenMastercard option
        /// The network that the token is associated with. An additional hash is included with a name matching this value, containing tokenization data specific to the card network.
        Type: IssuingNetworkTokenNetworkDataType
        Visa: IssuingNetworkTokenVisa option
        WalletProvider: IssuingNetworkTokenWalletProvider option
    }

